class Trie {
    private Trie[] children = new Trie[26];
    private boolean isEndOfWord = false;

    public void insert(String word) {
        Trie node = this;
        for (char c : word.toCharArray()) {
            int idx = c - 'a';
            if (node.children[idx] == null) node.children[idx] = new Trie();
            node = node.children[idx];
        }
        node.isEndOfWord = true;
    }

    public boolean search(String word) {
        Trie node = find(word);
        return node != null && node.isEndOfWord;
    }

    public boolean startsWith(String prefix) {
        return find(prefix) != null;
    }

    private Trie find(String s) {
        Trie node = this;
        for (char c : s.toCharArray()) {
            int idx = c - 'a';
            if (node.children[idx] == null) return null;
            node = node.children[idx];
        }
        return node;
    }
}

class WordDictionary {
    private WordDictionary[] children = new WordDictionary[26];
    private boolean isEndOfWord = false;

    public void addWord(String word) {
        WordDictionary node = this;
        for (char c : word.toCharArray()) {
            int idx = c - 'a';
            if (node.children[idx] == null) node.children[idx] = new WordDictionary();
            node = node.children[idx];
        }
        node.isEndOfWord = true;
    }

    public boolean search(String word) {
        return dfs(word, 0, this);
    }

    private boolean dfs(String word, int index, WordDictionary node) {
        if (node == null) return false;
        if (index == word.length()) return node.isEndOfWord;
        char c = word.charAt(index);
        if (c == '.') {
            for (WordDictionary child : node.children) {
                if (dfs(word, index + 1, child)) return true;
            }
            return false;
        }
        return dfs(word, index + 1, node.children[c - 'a']);
    }
}

class Solution {
    static class TrieNode {
        TrieNode[] children = new TrieNode[26];
        boolean isEndOfWord = false;
    }

    public String replaceWords(List<String> dictionary, String sentence) {
        TrieNode root = new TrieNode();
        for (String rootWord : dictionary) {
            TrieNode node = root;
            for (char c : rootWord.toCharArray()) {
                int idx = c - 'a';
                if (node.children[idx] == null) node.children[idx] = new TrieNode();
                node = node.children[idx];
            }
            node.isEndOfWord = true;
        }

        StringBuilder result = new StringBuilder();
        for (String word : sentence.split(" ")) {
            if (result.length() > 0) result.append(" ");
            result.append(shortestRoot(word, root));
        }
        return result.toString();
    }

    private String shortestRoot(String word, TrieNode root) {
        TrieNode node = root;
        StringBuilder prefix = new StringBuilder();
        for (char c : word.toCharArray()) {
            int idx = c - 'a';
            if (node.children[idx] == null) return word;
            prefix.append(c);
            node = node.children[idx];
            if (node.isEndOfWord) return prefix.toString();
        }
        return word;
    }
}

class MapSum {
